# Data validation and sanitization
def validate_csv_data(df):
    if df.empty:
        return False, "Empty dataset"
    if len(df.columns) < 2:
        return False, "Insufficient columns"
    return True, "Valid"

def sanitize_filename(filename):
    return secure_filename(filename)

def calculate_file_hash(filepath):
    hash_md5 = hashlib.md5()
    with open(filepath, "rb") as f:
        for chunk in iter(lambda: f.read(4096), b""):
            hash_md5.update(chunk)
    return hash_md5.hexdigest()

def verify_data_integrity(filepath, expected_hash):
    actual_hash = calculate_file_hash(filepath)
    return actual_hash == expected_hash

# ML Model Class
class CommunityMLModel:
    def __init__(self):
        self.model = None
        self.label_encoder = LabelEncoder()
        self.is_trained = False
        
    def create_model(self, num_classes, input_shape=(224, 224, 3)):
        model = tf.keras.Sequential([
            tf.keras.layers.Conv2D(32, (3, 3), activation='relu', input_shape=input_shape),
            tf.keras.layers.MaxPooling2D((2, 2)),
            tf.keras.layers.Conv2D(64, (3, 3), activation='relu'),
            tf.keras.layers.MaxPooling2D((2, 2)),
            tf.keras.layers.Conv2D(64, (3, 3), activation='relu'),
            tf.keras.layers.Flatten(),
            tf.keras.layers.Dense(64, activation='relu'),
            tf.keras.layers.Dense(num_classes, activation='softmax')
        ])
        model.compile(optimizer='adam',
                      loss='sparse_categorical_crossentropy',
                      metrics=['accuracy'])
        self.model = model
        
    def train(self, X_train, y_train, X_val, y_val, epochs=10):
        if not self.model:
            raise ValueError("Model not initialized")
            
        history = self.model.fit(X_train, y_train,
                                epochs=epochs,
                                validation_data=(X_val, y_val),
                                verbose=0)
        self.is_trained = True
        return history
        
    def predict(self, X):
        if not self.is_trained:
            raise ValueError("Model not trained")
        return self.model.predict(X)

